package com.oxclient.core.relay.listenerimport android.util.Base64import com.oxclient.ui.overlay.OverlayLoggerimport com.oxclient.auth.MicrosoftAuthManagerimport com.oxclient.core.relay.ClientIdentificationimport com.oxclient.core.relay.ConnectionManagerimport com.oxclient.core.relay.OxRelaySessionimport org.cloudburstmc.protocol.bedrock.data.PacketCompressionAlgorithmimport org.cloudburstmc.protocol.bedrock.data.auth.AuthPayloadimport org.cloudburstmc.protocol.bedrock.data.auth.AuthTypeimport org.cloudburstmc.protocol.bedrock.data.auth.CertificateChainPayloadimport org.cloudburstmc.protocol.bedrock.data.auth.TokenPayloadimport org.cloudburstmc.protocol.bedrock.packet.*import org.json.JSONArrayimport org.json.JSONObjectimport java.math.BigIntegerimport java.security.*import java.security.interfaces.ECPrivateKeyimport java.security.interfaces.ECPublicKeyimport java.security.spec.ECGenParameterSpec/** * LoginPacketListener — WRelay OnlineLoginPacketListener ile birebir akış. * * ═══════════════════════════════════════════════════════════════════ * AKIŞ: *  1. [C→R] RequestNetworkSettingsPacket *     → AutoCodecListener (priority=-10) halleder, biz sadece geçiririz * *  2. [C→R] LoginPacket *     → Chain inject *     → session.connectToServer() — İLK KEZ burada server'a bağlanılır *     → Paketi tutarız, server hazır olunca göndereceğiz *     → return false (server'a henüz iletme) * *  3. Server bağlantısı kurulunca onConnected callback: *     → Server'a RequestNetworkSettings gönder * *  4. [S→R] NetworkSettingsPacket *     → serverSession.setCompression() — server ZLIB açılır *     → Saklanan Login paketini server'a gönder *     → return false (client'a iletme — client zaten AutoCodec'ten aldı) * *  5. [S→R] ServerToClientHandshake *     → Şifreleme anahtarını üret *     → serverSession.enableEncryption() *     → Server'a ClientToServerHandshake gönder *     → Client'a da ilet (return true) * *  6. [C→R] ClientToServerHandshake *     → Server'a ilet (return true) * *  7. [S→R] PlayStatus(LOGIN_SUCCESS) → ConnectionManager.onHandshaking() *  8. [S→R] StartGame → ConnectionManager.onGameStarted() * ═══════════════════════════════════════════════════════════════════ */class LoginPacketListener : OxPacketListener {    companion object {        private const val TAG = "LoginPacketListener"    }    override val priority: Int = 0    @Volatile var clientIdentification: ClientIdentification? = null        private set    @Volatile private var loginProcessed = false    @Volatile private var pendingLogin  : LoginPacket? = null    @Volatile private var loginSentAtMs : Long = 0L    // ── DEBUG A/B TOGGLE ─────────────────────────────────────────────────    // "Invalid login data (identifier)" sebebini izole etmek için:    // true  → mevcut davranış (clientJwt chain key'i ile yeniden imzalanır)    // false → clientJwt'ye DOKUNULMAZ, orijinal (client'ın kendi imzaladığı)    //         haliyle olduğu gibi sunucuya gider (sadece chain enjekte edilir).    // Bu deneyin sonucu şunu netleştirir:    //   - false ile de AYNI hata geliyorsa → sorun resign adımında DEĞİL,    //     chain injection'ın kendisinde (örn. sunucu client'ın kendi    //     device key'ini bekliyor, bizim ürettiğimiz key'i değil).    //   - false ile FARKLI/hiç hata gelmiyorsa → resign adımı gerçekten    //     suçlu, imzalama detaylarına (derToRaw/payload sırası) bakılmalı.    private val resignClientJwtEnabled = true    // ── Lifecycle ─────────────────────────────────────────────────────────    override fun onSessionStart(session: OxRelaySession) {        // Server bağlantısı kurulunca çağrılır — Login akışı devam ediyor demek        OverlayLogger.d(TAG, "onSessionStart — server bağlandı")        ConnectionManager.onHandshaking()    }    override fun onSessionEnd(session: OxRelaySession) {        pendingLogin = null        loginSentAtMs = 0L        ConnectionManager.onDisconnected()    }    // ── Client → Relay ────────────────────────────────────────────────────    override fun onClientPacket(packet: BedrockPacket, session: OxRelaySession): Boolean {        when (packet) {            is RequestNetworkSettingsPacket -> {                // AutoCodecListener (priority=-10) zaten halletti                // Biz geçiriyoruz (server henüz yok, sendToServer kuyruğa alır)                OverlayLogger.d(TAG, "RequestNetworkSettings geçti — protocol=${packet.protocolVersion}")            }            is LoginPacket -> {                if (loginProcessed) {                    OverlayLogger.w(TAG, "Tekrarlanan Login engellendi")                    return false                }                loginProcessed = true                OverlayLogger.i(TAG, "Login alındı — server bağlantısı başlatılıyor")                // Kimlik bilgilerini parse et                val chainJson = extractChainJson(packet)                val extraJson = extractExtraJson(packet)                try {                    clientIdentification = ClientIdentification.fromLogin(chainJson, extraJson)                    OverlayLogger.i(TAG, "Client: $clientIdentification")                } catch (e: Exception) {                    OverlayLogger.w(TAG, "ClientIdentification parse hatası: ${e.message}")                }                // Xbox chain'i inject et                injectAuthChain(packet, session)                // Login'i sakla — server NetworkSettings gönderince iletiriz                pendingLogin = packet                // Server'a bağlan — callback: RequestNetworkSettings gönder                session.connectToServer {                    OverlayLogger.i(TAG, "Server hazır — RequestNetworkSettings gönderiliyor")                    val reqNet = RequestNetworkSettingsPacket().apply {                        protocolVersion = session.activeCodec.protocolVersion                    }                    session.sendToServer(reqNet)                }                // Paketi server'a iletme — biz yönettik                return false            }            is ClientToServerHandshakePacket -> {                OverlayLogger.d(TAG, "ClientToServerHandshake → iletiliyor")                // İlet            }        }        return true    }    // ── Server → Relay ────────────────────────────────────────────────────    override fun onServerPacket(packet: BedrockPacket, session: OxRelaySession): Boolean {        when (packet) {            // Server NetworkSettings → server compression aç → Login gönder            is NetworkSettingsPacket -> {                OverlayLogger.d(TAG, "Server NetworkSettings: algo=${packet.compressionAlgorithm} threshold=${packet.compressionThreshold}")                try {                    val algo = if (packet.compressionThreshold > 0)                        packet.compressionAlgorithm                    else                        PacketCompressionAlgorithm.NONE                    session.serverSession?.setCompression(algo)                    OverlayLogger.i(TAG, "Server compression: $algo")                } catch (e: Exception) {                    OverlayLogger.w(TAG, "Server compression ayarlanamadı: ${e.message}")                }                val login = pendingLogin                if (login != null) {                    OverlayLogger.i(TAG, "Login server'a gönderiliyor")                    loginSentAtMs = System.currentTimeMillis()                    session.sendToServer(login)                    pendingLogin = null                } else {                    OverlayLogger.e(TAG, "HATA: pendingLogin null — Login kaybedildi!")                    session.disconnect("Login paketi kayboldu")                }                // Client'a iletme — client zaten AutoCodecListener'dan NetworkSettings aldı                return false            }            // Server şifreleme başlatıyor            is ServerToClientHandshakePacket -> {                OverlayLogger.d(TAG, "ServerToClientHandshake alındı")                try {                    enableEncryption(packet, session)                } catch (e: Exception) {                    OverlayLogger.w(TAG, "Şifreleme başarısız (devam ediliyor): ${e.message}")                    // Şifreleme yoksa sadece handshake gönder                    session.sendToServer(ClientToServerHandshakePacket())                }                // Client'a da ilet                return true            }            is PlayStatusPacket -> {                OverlayLogger.d(TAG, "PlayStatus: ${packet.status}")                when (packet.status) {                    PlayStatusPacket.Status.LOGIN_SUCCESS -> {                        OverlayLogger.i(TAG, "Login başarılı ✓")                        ConnectionManager.onHandshaking()                    }                    PlayStatusPacket.Status.PLAYER_SPAWN -> {                        OverlayLogger.i(TAG, "Oyuncu spawn ✓")                        ConnectionManager.onGameStarted()                    }                    else -> {                        if (packet.status.name.contains("FAIL", ignoreCase = true))                            OverlayLogger.e(TAG, "Login BAŞARISIZ: ${packet.status}")                    }                }            }            is StartGamePacket -> {                OverlayLogger.i(TAG, "StartGame → oyun içi")                ConnectionManager.onGameStarted()            }            is DisconnectPacket -> {                val elapsed = if (loginSentAtMs > 0) System.currentTimeMillis() - loginSentAtMs else -1L                OverlayLogger.w(TAG, "Server Disconnect: ${packet.kickMessage}")                try {                    OverlayLogger.w(TAG, "  ↳ raw alanlar: reason=${packet.reason} " +                        "hideDisconnectionScreen=${packet.isMessageSkipped}")                } catch (e: Exception) {                    OverlayLogger.d(TAG, "  ↳ ek DisconnectPacket alanları okunamadı: ${e.message}")                }                if (elapsed in 0..5000) {                    OverlayLogger.e(TAG, "↳ Login gönderildikten ${elapsed}ms sonra disconnect — " +                        "sunucu LoginPacket/authPayload/clientJwt doğrulamasında reddetti.")                    OverlayLogger.e(TAG, "↳ Kontrol sırası: 1) chain[0] anahtar tutarlılığı  " +                        "2) JWT exp/nbf süresi  3) clientJwt imzası  4) ServerAddress/DeviceId alanları " +                        "— yukarıdaki 'Chain diagnostiği' ve 'clientJwt' loglarına bak.")                } else if (elapsed > 5000) {                    OverlayLogger.w(TAG, "↳ Login'den ${elapsed}ms sonra disconnect — muhtemelen auth " +                        "sonrası bir aşamada (encryption/StartGame) kopma, kimlik doğrulaması sorunu olmayabilir.")                }                loginSentAtMs = 0L            }        }        return true    }    // ── Şifreleme ─────────────────────────────────────────────────────────    private fun enableEncryption(packet: ServerToClientHandshakePacket, session: OxRelaySession) {        val jwt    = packet.jwt ?: throw IllegalStateException("JWT null")        val parts  = jwt.split(".")        require(parts.size == 3) { "Geçersiz JWT format" }        val decoder     = java.util.Base64.getUrlDecoder()        val headerJson  = JSONObject(String(decoder.decode(parts[0])))        val payloadJson = JSONObject(String(decoder.decode(parts[1])))        val x5u  = headerJson.getString("x5u")        val salt = java.util.Base64.getDecoder().decode(payloadJson.getString("salt"))        val serverPubKey = org.cloudburstmc.protocol.bedrock.util.EncryptionUtils.parseKey(x5u)        val privateKey   = MicrosoftAuthManager.getPrivateKeyForEncryption()            ?: throw IllegalStateException("Encryption private key yok")        val secretKey = org.cloudburstmc.protocol.bedrock.util.EncryptionUtils            .getSecretKey(privateKey, serverPubKey, salt)        session.serverSession?.enableEncryption(secretKey)        OverlayLogger.i(TAG, "Server şifreleme aktif ✓")        session.sendToServer(ClientToServerHandshakePacket())    }    // ── Auth Chain Inject ─────────────────────────────────────────────────    //    // v818+ ile LoginPacket.chain/extra alanları kaldırıldı, yerine geldi:    //   packet.authPayload : AuthPayload (CertificateChainPayload ya da TokenPayload)    //   packet.clientJwt    : String      (eski "extra"nın doğrudan karşılığı)    //    // AuthType.FULL — wclient'in OnlineLoginPacketListener.kt'sinde aynı    // pattern doğrulandı: loginPacket.authPayload = CertificateChainPayload(chain, AuthType.FULL)    //    // ═══════════════════════════════════════════════════════════════════    // KRİTİK FİX — "Invalid login data (identifier)" sebebi:    // ──────────────────────────────────────────────────────    // MicrosoftAuthManager.fetchMinecraftChain() ZATEN kendi içinde bir    // keypair üretip onunla imzalanmış bir "deviceJwt"yi chain'in başına    // ekliyor — yani getActiveChainForRelay()'den dönen chain, baştan sona    // kriptografik olarak TUTARLI ve TAMAMLANMIŞ bir zincir.    //    // Önceki sürümde burada İKİNCİ bir rastgele keypair daha üretilip    // ikinci bir deviceJwt zincirin başına ekleniyordu. Çözüm: ekstra    // keypair/deviceJwt üretmeyi tamamen kaldırıp kayıtlı chain'i OLDUĞU    // GİBİ kullanmak.    //    // İKİNCİ HATA: clientJwt (skin/client data) — sunucu bunun imzasını    // chain'in ilk linkinin public key'ine göre doğruluyor. Client'ın    // kendi clientJwt'si KENDİ key'iyle imzalı, bizim chain'imizle alakası    // yok. Bu yüzden clientJwt'yi de AYNI key ile yeniden imzalıyoruz.    //    // ÜÇÜNCÜ HATA: Mojang Bedrock auth secp384r1 (P-384) + ES384 kullanır —    // önceden kullanılan secp256r1/ES256 tek başına reddedilme sebebiydi.    // ═══════════════════════════════════════════════════════════════════    private fun injectAuthChain(packet: LoginPacket, session: OxRelaySession) {        val savedChain = MicrosoftAuthManager.getActiveChainForRelay()        if (savedChain.isNullOrBlank()) {            OverlayLogger.w(TAG, "Kayıtlı chain yok — offline mod (orijinal authPayload iletiliyor)")            return        }        val privKeyB64 = MicrosoftAuthManager.getActivePrivateKeyForRelay()        if (privKeyB64.isNullOrBlank()) {            OverlayLogger.e(TAG, "Kayıtlı private key yok — chain enjeksiyonu atlandı (tekrar login gerekebilir)")            return        }        val pubKeyB64 = MicrosoftAuthManager.getActivePublicKeyForRelay()        if (pubKeyB64.isNullOrBlank()) {            OverlayLogger.e(TAG, "Kayıtlı public key yok — chain enjeksiyonu atlandı (tekrar login gerekebilir)")            return        }        OverlayLogger.d(TAG, "injectAuthChain başladı — hedef=${session.remoteHost}:${session.remotePort}")        OverlayLogger.d(TAG, "  pubKeyB64  (ilk 32) = ${pubKeyB64.take(32)}…  (len=${pubKeyB64.length})")        OverlayLogger.d(TAG, "  privKeyB64 (ilk 16) = ${privKeyB64.take(16)}…  (len=${privKeyB64.length})")        try {            val savedJwts = parseSavedChain(savedChain)            if (savedJwts.isEmpty()) {                OverlayLogger.e(TAG, "Kayıtlı chain boş/parse edilemedi — enjeksiyon atlandı")                return            }            // ── DIAGNOSTIK #1 — chain'in kendisi tutarlı mı? ────────────────            // exp/nbf süresi dolmuş mu, chain[0].identityPublicKey kayıtlı            // pubKeyB64 ile eşleşiyor mu (eşleşmezse imza zinciri baştan            // kırık demektir — sunucu "identifier" ile anında reddeder).            logChainDiagnostics(savedJwts, pubKeyB64)            packet.authPayload = CertificateChainPayload(savedJwts, AuthType.FULL)            OverlayLogger.i(TAG, "Chain enjekte edildi [authPayload]: ${savedJwts.size} JWT (orijinal, değiştirilmeden), authType=FULL")            // ── clientJwt (skin/client data) yeniden imzalama — KRİTİK ─────            // Sunucu clientJwt'nin imzasını chain'in ilk linkinin public            // key'ine göre doğruluyor. Orijinal client kendi key'iyle            // imzalamış, bizim chain'imizle alakası yok — payload'ı AYNI            // key ile yeniden imzalıyoruz. Ayrıca ServerAddress/DeviceId            // alanları client'ın RELAY'e bağlandığı bilgiyi taşıdığı için            // gerçek hedefe göre override ediliyor (bkz. resignClientJwt).            val originalClientJwt = packet.clientJwt            if (!originalClientJwt.isNullOrBlank()) {                OverlayLogger.d(TAG, "── clientJwt (ORİJİNAL, client'tan geldi) ──")                logClientJwtFields(originalClientJwt)                if (!resignClientJwtEnabled) {                    OverlayLogger.w(TAG, "★ DEBUG: resignClientJwtEnabled=false — clientJwt DOKUNULMADAN gönderiliyor (A/B testi)")                } else {                    val resigned = resignClientJwt(originalClientJwt, privKeyB64, pubKeyB64, session)                    if (resigned != null) {                        packet.clientJwt = resigned                        OverlayLogger.i(TAG, "clientJwt yeniden imzalandı ✓ (chain key'i ile)")                        OverlayLogger.d(TAG, "── clientJwt (YENİDEN İMZALANMIŞ, sunucuya gidecek) ──")                        logClientJwtFields(resigned)                    } else {                        OverlayLogger.e(TAG, "clientJwt yeniden imzalanamadı — login muhtemelen reddedilecek")                    }                }            } else {                OverlayLogger.w(TAG, "clientJwt boş — skin data yok")            }        } catch (e: Exception) {            OverlayLogger.e(TAG, "Chain inject hatası: ${e.message}", e)        }    }    // ── Diagnostik Yardımcıları ──────────────────────────────────────────    //    // Bu fonksiyonlar hiçbir imzalama/enjeksiyon mantığını DEĞİŞTİRMİYOR,    // sadece sunucunun neden reddettiğini anlamak için chain/clientJwt    // içeriğini okunabilir şekilde loglar. "Invalid login data (identifier)"    // hatası genellikle şu 3 sebepten biridir — hepsi burada kontrol edilir:    //   1. chain[0].identityPublicKey ≠ kayıtlı pubKeyB64 (anahtar tutarsız)    //   2. Chain JWT'lerden biri süresi dolmuş (exp geçmiş / nbf gelecekte)    //   3. clientJwt'deki ServerAddress/DeviceId gerçek bağlantıyla uyuşmuyor    private fun decodeJwtPart(b64UrlPart: String): JSONObject? = try {        val padded = b64UrlPart + "=".repeat((4 - b64UrlPart.length % 4) % 4)        val bytes  = Base64.decode(padded, Base64.URL_SAFE or Base64.NO_WRAP)        JSONObject(String(bytes, Charsets.UTF_8))    } catch (e: Exception) {        OverlayLogger.w(TAG, "JWT parça decode edilemedi: ${e.message}")        null    }    private fun logChainDiagnostics(chainJwts: List<String>, expectedPubKeyB64: String) {        val nowSec = System.currentTimeMillis() / 1000L        OverlayLogger.i(TAG, "── Chain diagnostiği (${chainJwts.size} JWT) ──")        chainJwts.forEachIndexed { idx, jwt ->            val parts = jwt.split(".")            if (parts.size != 3) {                OverlayLogger.e(TAG, "  [$idx] geçersiz JWT formatı (${parts.size} parça, beklenen 3)")                return@forEachIndexed            }            val header  = decodeJwtPart(parts[0])            val payload = decodeJwtPart(parts[1])            val alg     = header?.optString("alg") ?: "?"            val x5u     = header?.optString("x5u")?.takeIf { it.isNotBlank() }            val certAuthority  = payload?.optBoolean("certificateAuthority", false) ?: false            val identityPubKey = payload?.optString("identityPublicKey")?.takeIf { it.isNotBlank() }            val extraDataObj   = payload?.optJSONObject("extraData")            val hasExtraData   = extraDataObj != null            val xuid = extraDataObj?.optString("XUID")            val displayName = extraDataObj?.optString("displayName")            val identityUuid = extraDataObj?.optString("identity")            val titleId = extraDataObj?.optString("titleId")            val sandboxId = extraDataObj?.optString("sandboxId")            val exp = payload?.optLong("exp", -1L) ?: -1L            val nbf = payload?.optLong("nbf", -1L) ?: -1L            val iat = payload?.optLong("iat", -1L) ?: -1L            val expStatus = when {                exp < 0      -> "yok"                exp < nowSec -> "★ SÜRESİ DOLMUŞ (${nowSec - exp}s önce) ★"                else         -> "geçerli (${exp - nowSec}s kaldı)"            }            val nbfStatus = if (nbf > 0 && nbf > nowSec) "★ HENÜZ BAŞLAMADI (${nbf - nowSec}s sonra) ★" else "ok"            OverlayLogger.i(TAG, "  [$idx] alg=$alg certAuthority=$certAuthority extraData=$hasExtraData" +                if (hasExtraData) " xuid=${xuid ?: "-"} name=${displayName ?: "-"}" else "")            OverlayLogger.i(TAG, "        exp=$expStatus nbf=$nbfStatus iat=$iat x5u=${x5u?.take(28) ?: "-"}…")            if (hasExtraData) {                // extraData içindeki TÜM alanları ham haliyle logla — özellikle                // 'identity' (UUID) alanı boş/geçersizse PocketMine-MP tabanlı                // sunucular tam olarak "Invalid login data (identifier)" atar.                OverlayLogger.i(TAG, "        extraData.identity(UUID)=${identityUuid ?: "★ YOK/BOŞ ★"} " +                    "titleId=${titleId ?: "-"} sandboxId=${sandboxId ?: "-"}")                if (identityUuid.isNullOrBlank()) {                    OverlayLogger.e(TAG, "        ↳ ★★★ extraData.identity (UUID) EKSİK/BOŞ ★★★ — " +                        "PocketMine-MP'nin login doğrulayıcısı bu alanı zorunlu tutar; " +                        "eksikse tam bu sebeple 'identifier' hatası fırlatır.")                } else {                    val uuidRegex = Regex("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$")                    if (!uuidRegex.matches(identityUuid)) {                        OverlayLogger.e(TAG, "        ↳ ★★★ extraData.identity GEÇERLİ BİR UUID DEĞİL: '$identityUuid' ★★★")                    }                }            }            if (exp in 1 until nowSec) {                OverlayLogger.e(TAG, "        ↳ BU JWT SÜRESİ DOLMUŞ — sunucu chain'i tamamen reddedebilir!")            }            // chain[0] = self-signed device sertifikası: identityPublicKey            // buradan itibaren chain[1]'in imzasını doğrulamak için trust            // anchor olarak kullanılır. Kayıtlı public key ile eşleşmiyorsa            // relay'in kendi ürettiği key ile Mojang'a kayıtlı key TUTARSIZ            // demektir — "identifier" hatasının en klasik sebebi budur.            if (idx == 0) {                when {                    identityPubKey == null ->                        OverlayLogger.e(TAG, "        ↳ chain[0].identityPublicKey YOK — self-signed sertifika eksik!")                    identityPubKey == expectedPubKeyB64 ->                        OverlayLogger.i(TAG, "        ↳ chain[0].identityPublicKey ✓ kayıtlı pubKeyB64 ile eşleşiyor")                    else -> {                        OverlayLogger.e(TAG, "        ↳ ★★★ ANAHTAR UYUŞMUYOR ★★★ chain[0].identityPublicKey ≠ kayıtlı pubKeyB64")                        OverlayLogger.e(TAG, "          chain[0] : ${identityPubKey.take(40)}…")                        OverlayLogger.e(TAG, "          kayıtlı  : ${expectedPubKeyB64.take(40)}…")                        OverlayLogger.e(TAG, "          → Bu tutarsızlık TEK BAŞINA 'Invalid login data (identifier)' sebebi olabilir.")                    }                }            }            // ── KRİTİK: son link (extraData olan, chain[2]) ─────────────────            // clientJwt (skin/client data) imzasının doğrulanması gereken            // anahtar chain[0] DEĞİL — protokolde zincirin SON linkinin            // identityPublicKey'idir. Bu link Mojang tarafından üretilir ve            // normal şartlarda pubKeyB64'e eşit olmalı (Mojang'a /authentication            // isteğinde aynı pubKeyB64 identityPublicKey olarak gönderiliyor).            // Şu ana kadar bu link hiç kontrol edilmiyordu — resignClientJwt'nin            // imzaladığı key ile bu alan uyuşmazsa sunucu clientJwt imzasını            // doğrulayamaz ve reddeder.            if (idx == chainJwts.lastIndex && hasExtraData) {                when {                    identityPubKey == null ->                        OverlayLogger.e(TAG, "        ↳ chain[SON].identityPublicKey YOK — clientJwt'nin hangi key ile imzalanması gerektiği belli değil!")                    identityPubKey == expectedPubKeyB64 ->                        OverlayLogger.i(TAG, "        ↳ chain[SON].identityPublicKey ✓ clientJwt'yi imzaladığımız pubKeyB64 ile eşleşiyor")                    else -> {                        OverlayLogger.e(TAG, "        ↳ ★★★★★ ASIL SORUN BURADA OLABİLİR ★★★★★")                        OverlayLogger.e(TAG, "          chain[SON].identityPublicKey ≠ resignClientJwt'de kullanılan pubKeyB64")                        OverlayLogger.e(TAG, "          chain[SON] : ${identityPubKey.take(40)}…")                        OverlayLogger.e(TAG, "          kullanılan : ${expectedPubKeyB64.take(40)}…")                        OverlayLogger.e(TAG, "          → Sunucu clientJwt imzasını BU anahtara göre doğrular; " +                            "eşleşmezse chain[0] eşleşse bile 'Invalid login data (identifier)' alırsın.")                    }                }            }        }    }    private fun logClientJwtFields(jwt: String) {        val parts = jwt.split(".")        if (parts.size != 3) {            OverlayLogger.e(TAG, "  clientJwt formatı geçersiz (${parts.size} parça)")            return        }        val header  = decodeJwtPart(parts[0])        val payload = decodeJwtPart(parts[1])        OverlayLogger.d(TAG, "  header.alg=${header?.optString("alg")} x5u=${header?.optString("x5u")?.take(28)}…")        if (payload == null) {            OverlayLogger.w(TAG, "  payload decode edilemedi")            return        }        // Sunucuların identity/relay tespiti için en sık kontrol ettiği alanlar.        listOf(            "ServerAddress", "DeviceId", "DeviceOS", "ClientRandomId", "SelfSignedId",            "GameVersion", "PlayFabId", "ThirdPartyName", "LanguageCode",            "CurrentInputMode", "DefaultInputMode", "UIProfile"        ).forEach { key ->            if (payload.has(key)) OverlayLogger.d(TAG, "  $key = ${payload.opt(key)}")        }        OverlayLogger.d(TAG, "  (payload toplam alan sayısı = ${payload.length()})")        if (payload.has("PlayFabId")) {            OverlayLogger.w(TAG, "  ↳ PlayFabId mevcut AMA hesabın gerçek kimliğine bağlı DEĞİL " +                "(MicrosoftAuthManager PlayFab login yapmıyor) — sunucu bunu doğruluyorsa reddedilebilir.")        }    }    // ── JWT / Base64 Yardımcıları ─────────────────────────────────────────    private fun parseSavedChain(json: String): List<String> = try {        when {            json.trimStart().startsWith("{") -> {                val arr = JSONObject(json).optJSONArray("chain")                if (arr != null) (0 until arr.length()).map { arr.getString(it) }                else emptyList()            }            json.trimStart().startsWith("[") -> {                val arr = JSONArray(json)                (0 until arr.length()).map { arr.getString(it) }            }            else -> listOf(json)        }    } catch (e: Exception) {        OverlayLogger.w(TAG, "Chain parse hatası: ${e.message}")        emptyList()    }    private fun buildDeviceJwt(priv: ECPrivateKey, pubB64: String): String {        val now     = System.currentTimeMillis() / 1000L        // Mojang Bedrock auth secp384r1 (P-384) + ES384 kullanır.        val header  = b64Url("""{"alg":"ES384","x5u":"$pubB64"}""".toByteArray())        val payload = b64Url(            ("""{"certificateAuthority":true,"identityPublicKey":"$pubB64",""" +             """"exp":${now + 86400},"nbf":${now - 1},"iat":$now,"iss":"Minecraft"}""")                .toByteArray()        )        val data = "$header.$payload"        val sig  = Signature.getInstance("SHA384withECDSA").apply {            initSign(priv)            update(data.toByteArray(Charsets.US_ASCII))        }.sign()        return "$data.${b64Url(derToRaw(sig))}"    }    private fun derToRaw(der: ByteArray): ByteArray {        var i = 2        i++ // skip r tag 0x02        val rLen = der[i++].toInt() and 0xFF        val r = der.copyOfRange(i, i + rLen); i += rLen        i++ // skip s tag 0x02        val sLen = der[i++].toInt() and 0xFF        val s = der.copyOfRange(i, i + sLen)        // P-384 imza bileşenleri 48 byte'tır (P-256'da 32 idi)        return pad48(BigInteger(1, r).toByteArray()) + pad48(BigInteger(1, s).toByteArray())    }    private fun pad48(b: ByteArray): ByteArray = when {        b.size == 48 -> b        b.size >  48 -> b.copyOfRange(b.size - 48, b.size)        else         -> ByteArray(48 - b.size) + b    }    /**     * clientJwt'nin (skin/client data) PAYLOAD'ını alıp:     *   1. ServerAddress'i client'ın relay'e bağlandığı adresten GERÇEK     *      hedef sunucunun adresine (session.remoteHost:remotePort) çevirir     *   2. DeviceId'yi yeniler     * ardından MicrosoftAuthManager'da saklanan chain key'i ile yeniden imzalar.     *     * NEDEN: Gerçek MCPE client relay'e (LAN) bağlanıyor, bu yüzden kendi     * ClientData JWT'sinde ServerAddress = relay'in adresi olur — asıl hedef     * (2b2tpe.org:19132) DEĞİL. Anti-relay/strict sunucular bu alanı     * bağlantının geldiği gerçek adresle çapraz doğruluyor olabilir; eşleşmezse     * "Invalid login data (identifier)" ile reddedilir. wclient referansı     * (AuthUtils.fetchOnlineSkinData) aynı overrideleri yapıyor.     */    private fun resignClientJwt(originalClientJwt: String, privKeyB64: String, pubKeyB64: String, session: OxRelaySession): String? {        try {            val parts = originalClientJwt.split(".")            if (parts.size != 3) {                OverlayLogger.e(TAG, "clientJwt formatı geçersiz (3 parça bekleniyor, ${parts.size} bulundu)")                return null            }            val payloadJson = try {                val padded  = parts[1] + "=".repeat((4 - parts[1].length % 4) % 4)                val decoded = String(Base64.decode(padded, Base64.URL_SAFE or Base64.NO_WRAP), Charsets.UTF_8)                val obj = JSONObject(decoded)                val oldServerAddress = obj.optString("ServerAddress", "-")                val oldDeviceId      = obj.optString("DeviceId", "-")                val newServerAddress = "${session.remoteHost}:${session.remotePort}"                val newDeviceId      = java.util.UUID.randomUUID().toString()                obj.put("ServerAddress", newServerAddress)                obj.put("DeviceId", newDeviceId)                OverlayLogger.i(TAG, "  ServerAddress override: '$oldServerAddress' → '$newServerAddress'")                OverlayLogger.i(TAG, "  DeviceId override     : '$oldDeviceId' → '$newDeviceId'")                b64Url(obj.toString().toByteArray(Charsets.UTF_8))            } catch (e: Exception) {                OverlayLogger.w(TAG, "clientJwt payload override edilemedi, ORİJİNAL payload kullanılıyor: ${e.message}")                parts[1]            }            val keyBytes = Base64.decode(privKeyB64, Base64.NO_WRAP)            val privKey  = KeyFactory.getInstance("EC")                .generatePrivate(java.security.spec.PKCS8EncodedKeySpec(keyBytes)) as ECPrivateKey            val header = b64Url("""{"alg":"ES384","x5u":"$pubKeyB64"}""".toByteArray())            val data   = "$header.$payloadJson"            val sig    = Signature.getInstance("SHA384withECDSA").apply {                initSign(privKey)                update(data.toByteArray(Charsets.US_ASCII))            }.sign()            return "$data.${b64Url(derToRaw(sig))}"        } catch (e: Exception) {            OverlayLogger.e(TAG, "clientJwt yeniden imzalama hatası: ${e.message}", e)            return null        }    }    private fun b64Url(data: ByteArray) =        Base64.encodeToString(data, Base64.URL_SAFE or Base64.NO_WRAP or Base64.NO_PADDING)    private fun extractChainJson(packet: LoginPacket): String = try {        when (val auth = packet.authPayload) {            is CertificateChainPayload -> JSONObject().apply {                put("chain", JSONArray(auth.chain))            }.toString()            is TokenPayload -> JSONObject().apply {                put("token", auth.token)            }.toString()            else -> "{}"        }    } catch (_: Exception) { "{}" }    private fun extractExtraJson(packet: LoginPacket): String = try {        packet.clientJwt ?: ""    } catch (_: Exception) { "" }}